meta.script:
MathJax.Hub.Config({
  messageStyle: "none",
  extensions: ["tex2jax.js"],
  jax: ["input/TeX", "output/HTML-CSS"],
  tex2jax: {
    inlineMath: [ ['$','$'], ["\\(","\\)"] ],
    displayMath: [ ['$$','$$'], ["\\[","\\]"] ],
    processEscapes: true,
    ignoreClass: '.*',
    processClass: 'mathjax.*'
  },
  TeX: {
      extensions: ["AMSmath.js", "AMSsymbols.js", "noErrors.js"],
      noErrors: {
        inlineDelimiters: ["$","$"],
        multiLine: false,
        style: {
          "font-size": "normal",
          "border": ""
        }
      }
  },
  "HTML-CSS": { availableFonts: ["TeX"] }
});
